// Compute today's month + day + current year for the lookup.
// Cron fires at 12:00 UTC daily, which is 08:00 America/Toronto in
// summer (EDT) and 07:00 in winter (EST) — close enough to a morning
// send window for Mary's audience.
const now = new Date();
const month = now.getUTCMonth() + 1;
const day   = now.getUTCDate();
const year  = now.getUTCFullYear();
return { json: { month: month, day: day, year: year } };

// Filter to leads whose DOB falls on today's month+day. We do this in JS
// rather than the PostgREST URL because PostgREST doesn't expose
// date_part() directly through select filters. The query already excludes
// leads that received this year's birthday video, so the candidate set
// is small (everyone with a DOB who hasn't been sent yet this year).
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const ctx = $('Today Context').first().json;
const rows = allOf('Fetch Candidate Leads');
const todays = rows.filter(function (r) {
  if (!r || !r.date_of_birth) return false;
  const dob = new Date(r.date_of_birth + 'T00:00:00Z');
  return (dob.getUTCMonth() + 1) === ctx.month && dob.getUTCDate() === ctx.day;
});
if (!todays.length) {
  return [{ json: { _no_birthdays: true, month: ctx.month, day: ctx.day, year: ctx.year, candidates_checked: rows.length } }];
}
return todays.map(function (r) {
  return { json: {
    lead_id: r.id,
    client_id: r.client_id,
    full_name: r.full_name || '',
    first_name: r.first_name || ((r.full_name || '').split(' ')[0] || ''),
    year: ctx.year
  } };
});

// Final summary. Counts how many birthdays fired today, how many
// orchestrator calls succeeded, how many were marked sent. Useful when
// debugging via execution history.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const triggers = allOf('Trigger Birthday Video');
const marks = allOf('Mark Sent');
const fired = triggers.filter(function (t) { return t && t.ok !== false && !t.error; }).length;
return { json: {
  ok: true,
  birthdays_today: triggers.length,
  videos_fired: fired,
  marked_sent: marks.length,
  ts: new Date().toISOString()
} };
